#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/*
 * Hypervisor Resource Allocator Simulation
 * Demonstrates the Infrastructure Layer (IaaS) of cloud architecture
 * A hypervisor abstracts physical hardware to create virtual machines
 */

#define MAX_VMS 100
#define MAX_HOSTS 10

// VM states in compute cloud
typedef enum {
    VM_PENDING,
    VM_RUNNING,
    VM_STOPPED,
    VM_TERMINATED
} VMState;

// Storage types
typedef enum {
    STORAGE_OBJECT,    // S3-like: flat namespace, great for unstructured data
    STORAGE_BLOCK,    // EBS-like: raw volumes, low latency for databases
    STORAGE_FILE      // EFS-like: NFS/SMB protocols, shared access
} StorageType;

// Virtual Machine structure (Guest)
typedef struct {
    char vm_id[32];
    int vcpu_count;      // Virtual CPUs
    int vram_mb;         // Virtual RAM in MB
    char host_id[32];    // Physical host running this VM
    VMState state;
} VirtualMachine;

// Storage Volume structure
typedef struct {
    char volume_id[32];
    StorageType type;
    int size_gb;
    char attached_vm[32];
    int replication_factor;  // For durability in object storage
} StorageVolume;

// Physical Host (Hardware Layer)
typedef struct {
    char host_id[32];
    int total_cpu_cores;
    int total_ram_mb;
    int used_cpu_cores;
    int used_ram_mb;
} PhysicalHost;

// Cloud Platform Manager (Orchestrator)
typedef struct {
    PhysicalHost hosts[MAX_HOSTS];
    VirtualMachine vms[MAX_VMS];
    StorageVolume volumes[MAX_VMS];
    int host_count;
    int vm_count;
    int volume_count;
} CloudPlatform;

// Initialize cloud platform
void init_cloud(CloudPlatform *cloud) {
    cloud->host_count = 2;
    cloud->vm_count = 0;
    cloud->volume_count = 0;

    // Initialize physical hosts (Hardware Layer)
    strcpy(cloud->hosts[0].host_id, "host-001");
    cloud->hosts[0].total_cpu_cores = 32;
    cloud->hosts[0].total_ram_mb = 65536;  // 64GB
    cloud->hosts[0].used_cpu_cores = 0;
    cloud->hosts[0].used_ram_mb = 0;

    strcpy(cloud->hosts[1].host_id, "host-002");
    cloud->hosts[1].total_cpu_cores = 32;
    cloud->hosts[1].total_ram_mb = 65536;
    cloud->hosts[1].used_cpu_cores = 0;
    cloud->hosts[1].used_ram_mb = 0;

    printf("Cloud Platform initialized with %d physical hosts\n", cloud->host_count);
}

// Hypervisor creates a VM on a host (Resource Pooling)
int create_vm(CloudPlatform *cloud, char *vm_id, int vcpu, int vram) {
    if (cloud->vm_count >= MAX_VMS) {
        printf("Error: Maximum VMs reached\n");
        return -1;
    }

    // Find host with enough resources (Resource Pooling)
    int selected_host = -1;
    for (int i = 0; i < cloud->host_count; i++) {
        int available_cpu = cloud->hosts[i].total_cpu_cores - cloud->hosts[i].used_cpu_cores;
        int available_ram = cloud->hosts[i].total_ram_mb - cloud->hosts[i].used_ram_mb;

        if (available_cpu >= vcpu && available_ram >= vram) {
            selected_host = i;
            break;
        }
    }

    if (selected_host == -1) {
        printf("Error: No host has sufficient resources for VM %s\n", vm_id);
        return -1;
    }

    // Create VM (Hypervisor creates guest)
    VirtualMachine *vm = &cloud->vms[cloud->vm_count];
    strcpy(vm->vm_id, vm_id);
    vm->vcpu_count = vcpu;
    vm->vram_mb = vram;
    strcpy(vm->host_id, cloud->hosts[selected_host].host_id);
    vm->state = VM_RUNNING;

    // Update host resource usage
    cloud->hosts[selected_host].used_cpu_cores += vcpu;
    cloud->hosts[selected_host].used_ram_mb += vram;

    cloud->vm_count++;
    printf("[HYPERVISOR] Created VM '%s' on %s: %d vCPUs, %dMB RAM\n", 
           vm_id, vm->host_id, vcpu, vram);

    return 0;
}

// Create storage volume
int create_storage(CloudPlatform *cloud, char *volume_id, StorageType type, int size_gb) {
    if (cloud->volume_count >= MAX_VMS) {
        printf("Error: Maximum volumes reached\n");
        return -1;
    }

    StorageVolume *vol = &cloud->volumes[cloud->volume_count];
    strcpy(vol->volume_id, volume_id);
    vol->type = type;
    vol->size_gb = size_gb;
    strcpy(vol->attached_vm, "");

    // Object storage has replication for durability
    vol->replication_factor = (type == STORAGE_OBJECT) ? 3 : 1;

    const char *type_str[] = {"Object", "Block", "File"};
    printf("[STORAGE] Created %s volume '%s': %dGB (replication: %dx)\n",
           type_str[type], volume_id, size_gb, vol->replication_factor);

    cloud->volume_count++;
    return 0;
}

// Attach block storage to VM
int attach_storage(CloudPlatform *cloud, char *volume_id, char *vm_id) {
    for (int i = 0; i < cloud->volume_count; i++) {
        if (strcmp(cloud->volumes[i].volume_id, volume_id) == 0) {
            strcpy(cloud->volumes[i].attached_vm, vm_id);
            printf("[STORAGE] Attached volume '%s' to VM '%s'\n", volume_id, vm_id);
            return 0;
        }
    }
    return -1;
}

// Terminate VM (scale in)
int terminate_vm(CloudPlatform *cloud, char *vm_id) {
    for (int i = 0; i < cloud->vm_count; i++) {
        if (strcmp(cloud->vms[i].vm_id, vm_id) == 0) {
            // Find and update host
            for (int h = 0; h < cloud->host_count; h++) {
                if (strcmp(cloud->hosts[h].host_id, cloud->vms[i].host_id) == 0) {
                    cloud->hosts[h].used_cpu_cores -= cloud->vms[i].vcpu_count;
                    cloud->hosts[h].used_ram_mb -= cloud->vms[i].vram_mb;
                    break;
                }
            }
            cloud->vms[i].state = VM_TERMINATED;
            printf("[HYPERVISOR] Terminated VM '%s', resources returned to pool\n", vm_id);
            return 0;
        }
    }
    return -1;
}

// Display platform status
void display_status(CloudPlatform *cloud) {
    printf("\n=== Cloud Platform Status ===\n");
    printf("Hosts:\n");
    for (int i = 0; i < cloud->host_count; i++) {
        printf("  %s: %d/%d CPUs, %d/%d MB RAM used\n",
               cloud->hosts[i].host_id,
               cloud->hosts[i].used_cpu_cores, cloud->hosts[i].total_cpu_cores,
               cloud->hosts[i].used_ram_mb, cloud->hosts[i].total_ram_mb);
    }
    printf("VMs: %d running\n", cloud->vm_count);
    printf("Volumes: %d created\n", cloud->volume_count);
}

int main() {
    CloudPlatform cloud;
    init_cloud(&cloud);

    printf("\n=== Compute Cloud: Creating VMs (Scale Out) ===\n");
    create_vm(&cloud, "web-server-1", 2, 4096);
    create_vm(&cloud, "web-server-2", 2, 4096);
    create_vm(&cloud, "db-server", 4, 8192);

    printf("\n=== Storage Cloud: Creating Volumes ===\n");
    create_storage(&cloud, "backup-data", STORAGE_OBJECT, 500);   // Object storage
    create_storage(&cloud, "database-disk", STORAGE_BLOCK, 100); // Block storage
    create_storage(&cloud, "shared-files", STORAGE_FILE, 200);   // File storage

    attach_storage(&cloud, "database-disk", "db-server");

    display_status(&cloud);

    printf("\n=== Compute Cloud: Scaling In ===\n");
    terminate_vm(&cloud, "web-server-2");

    display_status(&cloud);

    return 0;
}
